1	//! Coroutine library — port of `lcorolib.c`.
2	//!
3	//! Provides the `coroutine.*` standard-library table: `create`, `resume`,
4	//! `running`, `status`, `wrap`, `yield`, `isyieldable`, and `close`.
5	//!
6	//! # Phase A–D stub notice
7	//!
8	//! Every function that requires actual coroutine execution (`resume`, `yield`,
9	//! cross-thread `xmove`, `new_thread`, `close_thread`) is **unimplemented** and
10	//! will panic at runtime.  The argument-checking and result-packaging logic is
11	//! translated faithfully so that Phase E can drop in the real implementations
12	//! without restructuring.  Phase E wires real stackful coroutines via
13	//! `corosensei`.  See PORTING.md §2 #6.
14	//!
15	//! Translated from: `reference/lua-5.4.7/src/lcorolib.c` (210 lines, 12 functions)
16	//! Target crate: `lua-stdlib`
17	
18	// TODO(port): LuaState, GcRef<LuaState>, LuaStatus, and related types live in
19	// lua-vm / lua-types; all unresolved imports will be fixed in Phase B.
20	use lua_types::{
21	    error::LuaError,
22	    value::LuaValue,
23	    LuaType,
24	    LuaStatus,
25	    gc::GcRef,
26	};
27	use crate::state_stub::{LuaState, LuaStateStubExt as _, lua_CFunction, upvalue_index, CompareOp, LuaDebug};
28	
29	// ── Coroutine status codes ────────────────────────────────────────────────────
30	
31	// C: #define COS_RUN   0
32	// C: #define COS_DEAD  1
33	// C: #define COS_YIELD 2
34	// C: #define COS_NORM  3
35	
36	/// Coroutine is the currently running thread.
37	const COS_RUN: i32 = 0;
38	
39	/// Coroutine has finished execution or encountered an error.
40	const COS_DEAD: i32 = 1;
41	
42	/// Coroutine is suspended — either yielded or not yet started.
43	const COS_YIELD: i32 = 2;
44	
45	/// Coroutine is normal — it resumed another coroutine and is waiting.
46	const COS_NORM: i32 = 3;
47	
48	/// Human-readable status strings indexed by the `COS_*` constants above.
49	/// Pushed onto the Lua stack as byte strings.
50	///
51	/// C: `static const char *const statname[] = {"running","dead","suspended","normal"};`
52	const STAT_NAMES: [&[u8]; 4] = [b"running", b"dead", b"suspended", b"normal"];
53	
54	// ── Registration table ────────────────────────────────────────────────────────
55	
56	/// Registration table for the `coroutine` standard library.
57	///
58	/// C: `static const luaL_Reg co_funcs[]`
59	///
60	/// Each entry is `(name_bytes, function_pointer)`. Phase B resolves
61	/// `lua_CFunction` to the canonical type alias from `lua-types`.
62	pub const CO_FUNCS: &[(&[u8], lua_CFunction)] = &[
63	    (b"create",      co_create),
64	    (b"resume",      co_resume),
65	    (b"running",     co_running),
66	    (b"status",      co_status),
67	    (b"wrap",        co_wrap),
68	    (b"yield",       co_yield),
69	    (b"isyieldable", co_isyieldable),
70	    (b"close",       co_close),
71	];
72	
73	// ── Internal helpers ──────────────────────────────────────────────────────────
74	
75	/// Retrieves the coroutine thread at stack index 1, raising a type error if
76	/// the argument is absent or not a thread.
77	///
78	/// C: `static lua_State *getco(lua_State *L)`
79	fn get_co(state: &mut LuaState) -> Result<GcRef<lua_types::value::LuaThread>, LuaError> {
80	    let co = state.to_thread(1);
81	    if co.is_none() {
82	        let got = state.arg(1);
83	        return Err(LuaError::type_arg_error(1, "thread", &got));
84	    }
85	    Ok(co.expect("checked above"))
86	}
87	
88	/// Returns one of the `COS_*` status codes describing `co` relative to the
89	/// calling thread `state`.
90	///
91	/// C: `static int auxstatus(lua_State *L, lua_State *co)`
92	fn aux_status(_state: &mut LuaState, _co: &GcRef<lua_types::value::LuaThread>) -> i32 {
93	    // TODO(phase-b): needs lua_vm cross-thread access to status, has_frames,
94	    // get_top, is_same_thread. Phase E wires real coroutines.
95	    todo!("phase-b: coroutine aux_status")
96	}
97	
98	/// Transfers `narg` arguments from `state` to `co`, resumes the coroutine,
99	/// then transfers results (or error message) back to `state`.
100	///
101	/// Returns the number of result values (≥ 0) on success, or `-1` on error
102	/// with the error object left on top of `state`'s stack.
103	///
104	/// C: `static int auxresume(lua_State *L, lua_State *co, int narg)`
105	fn aux_resume(state: &mut LuaState, _co: GcRef<lua_types::value::LuaThread>, _narg: i32) -> i32 {
106	    // TODO(port): coroutine stub — the complete body requires all of:
107	    //
108	    //   1. if !lua_checkstack(co, narg) { push "too many arguments"; return -1; }
109	    //      → co.ensure_stack(narg) — grow co's stack for the incoming arguments.
110	    //
111	    //   2. lua_xmove(L, co, narg)
112	    //      → state.xmove(&co, narg) — transfer narg values from L's stack to co's.
113	    //
114	    //   3. status = lua_resume(co, L, narg, &nres)
115	    //      → co.resume(state, narg) — execute co until it yields, returns, or errors.
116	    //        Returns (LuaStatus, nres: i32).
117	    //
118	    //   4. On LUA_OK / LUA_YIELD success path:
119	    //      if !lua_checkstack(L, nres + 1) { lua_pop(co, nres); push "too many results"; return -1; }
120	    //      lua_xmove(co, L, nres) — move results back.
121	    //      return nres;
122	    //
123	    //   5. On error path:
124	    //      lua_xmove(co, L, 1) — move error message back.
125	    //      return -1;
126	    //
127	    // All cross-thread operations depend on Phase E / corosensei runtime support.
128	    let _ = state;
129	    panic!(
130	        "coroutine.resume is not yet implemented (Phase A–D stub; see PORTING.md §2 #6)"
131	    );
132	}
133	
134	// ── Public library functions ──────────────────────────────────────────────────
135	
136	/// `coroutine.resume(co [, val1, ...])` — attempt to resume coroutine `co`.
137	///
138	/// On success pushes `true` followed by all values yielded or returned by `co`.
139	/// On failure pushes `false` followed by the error object.
140	///
141	/// C: `static int luaB_coresume(lua_State *L)`
142	pub fn co_resume(state: &mut LuaState) -> Result<usize, LuaError> {
143	    // C: lua_State *co = getco(L);
144	    let co = get_co(state)?;
145	    // C: r = auxresume(L, co, lua_gettop(L) - 1);
146	    // PORT NOTE: lua_gettop returns the argument count; -1 excludes the coroutine
147	    // itself which sits at index 1.
148	    let narg = state.get_top() - 1;
149	    let r = aux_resume(state, co, narg);
150	    if r < 0 {
151	        // C: lua_pushboolean(L, 0); lua_insert(L, -2); return 2;
152	        state.push(LuaValue::Bool(false));
153	        state.insert(-2);
154	        Ok(2)
155	    } else {
156	        // C: lua_pushboolean(L, 1); lua_insert(L, -(r + 1)); return r + 1;
157	        state.push(LuaValue::Bool(true));
158	        state.insert(-(r + 1));
159	        Ok((r + 1) as usize)
160	    }
161	}
162	
163	/// Closure body installed by `coroutine.wrap`.  The wrapped coroutine is
164	/// stored in upvalue slot 1.
165	///
166	/// On error the message is augmented with location info (if a string), then
167	/// re-raised.  If the coroutine is in an error state (not simply suspended),
168	/// its to-be-closed variables are cleaned up before propagation.
169	///
170	/// C: `static int luaB_auxwrap(lua_State *L)`
171	fn aux_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
172	    // C: lua_State *co = lua_tothread(L, lua_upvalueindex(1));
173	    // TODO(port): coroutine stub — upvalue_index(1) gives the first C-closure
174	    // upvalue pseudo-index; to_thread reads GcRef<LuaState> from that slot.
175	    let co = match state.to_thread(upvalue_index(1)) {
176	        Some(c) => c,
177	        None => panic!("coroutine.wrap: upvalue 1 is not a thread (Phase A–D stub)"),
178	    };
179	    // C: int r = auxresume(L, co, lua_gettop(L));
180	    let narg = state.get_top();
181	    let r = aux_resume(state, co.clone(), narg);
182	    let _ = co;
183	    if r < 0 {
184	        // TODO(phase-b): needs cross-thread status, close_thread, xmove.
185	        todo!("phase-b: coroutine wrap error path")
186	    } else {
187	        Ok(r as usize)
188	    }
189	}
190	
191	/// `coroutine.create(f)` — create a new coroutine that will run function `f`.
192	///
193	/// Pushes the new thread value and returns 1.
194	///
195	/// C: `static int luaB_cocreate(lua_State *L)`
196	pub fn co_create(state: &mut LuaState) -> Result<usize, LuaError> {
197	    // C: luaL_checktype(L, 1, LUA_TFUNCTION);
198	    state.check_arg_type(1, LuaType::Function)?;
199	    // C: NL = lua_newthread(L);
200	    // TODO(port): coroutine stub — new_thread allocates a fresh LuaState coroutine
201	    // and pushes a Thread value for it; Phase E needed.
202	    let _nl = state.new_thread()?;
203	    // C: lua_pushvalue(L, 1);          /* move function to top */
204	    // C: lua_xmove(L, NL, 1);          /* move function from L to NL */
205	    // PORT NOTE: in C the function copy is pushed and then xmove pops it
206	    // off L's stack into NL's. The Phase E xmove is not yet wired, but the
207	    // net stack effect on L is "thread on top". Skip the push entirely so
208	    // co_wrap's push_cclosure captures the thread (not the function) as
209	    // upvalue 1. Phase E will restore the push + xmove pair.
210	    // TODO(port): coroutine stub — xmove transfers the function from L's stack to
211	    // NL's stack so it becomes the coroutine body; Phase E needed.
212	    Ok(1)
213	}
214	
215	/// `coroutine.wrap(f)` — create a coroutine and return a resuming function.
216	///
217	/// The returned function, when called, resumes the coroutine as if by
218	/// `coroutine.resume`, but raises an error rather than returning `false`.
219	///
220	/// C: `static int luaB_cowrap(lua_State *L)`
221	pub fn co_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
222	    // C: luaB_cocreate(L);
223	    co_create(state)?;
224	    // C: lua_pushcclosure(L, luaB_auxwrap, 1);
225	    // TODO(port): push_cclosure(aux_wrap, 1) creates a C closure with the thread
226	    // (currently on top of the stack) as upvalue 1; Phase B wire-up needed.
227	    state.push_cclosure(aux_wrap, 1)?;
228	    Ok(1)
229	}
230	
231	/// `coroutine.yield([...])` — suspend the running coroutine.
232	///
233	/// All arguments are passed back as results of the corresponding `resume`.
234	///
235	/// C: `static int luaB_yield(lua_State *L)`
236	pub fn co_yield(state: &mut LuaState) -> Result<usize, LuaError> {
237	    // C: return lua_yield(L, lua_gettop(L));
238	    // TODO(port): coroutine stub — state.yield_(n) suspends the coroutine and
239	    // transfers n values back to the caller of resume; Phase E needed.
240	    let _nargs = state.get_top();
241	    panic!(
242	        "coroutine.yield is not yet implemented (Phase A–D stub; see PORTING.md §2 #6)"
243	    );
244	}
245	
246	/// `coroutine.status(co)` — return a string describing `co`'s current status.
247	///
248	/// Returns one of `"running"`, `"dead"`, `"suspended"`, or `"normal"`.
249	///
250	/// C: `static int luaB_costatus(lua_State *L)`
251	pub fn co_status(state: &mut LuaState) -> Result<usize, LuaError> {
252	    // C: lua_State *co = getco(L);
253	    let co = get_co(state)?;
254	    // C: lua_pushstring(L, statname[auxstatus(L, co)]);
255	    let idx = aux_status(state, &co) as usize;
256	    let name: &[u8] = STAT_NAMES[idx];
257	    let interned = state.intern_str(name)?;
258	    state.push(LuaValue::Str(interned));
259	    Ok(1)
260	}
261	
262	/// `coroutine.isyieldable([co])` — test whether a coroutine (default: current)
263	/// is in a yieldable state.
264	///
265	/// C: `static int luaB_yieldable(lua_State *L)`
266	pub fn co_isyieldable(state: &mut LuaState) -> Result<usize, LuaError> {
267	    let is_yieldable = if matches!(state.type_at(1), LuaType::None) {
268	        state.is_yieldable()
269	    } else {
270	        let _co = get_co(state)?;
271	        // TODO(phase-b): needs cross-thread is_yieldable; Phase E.
272	        todo!("phase-b: cross-thread is_yieldable")
273	    };
274	    state.push(LuaValue::Bool(is_yieldable));
275	    Ok(1)
276	}
277	
278	/// `coroutine.running()` — return the current coroutine plus a boolean.
279	///
280	/// The boolean is `true` when the current coroutine is the main thread.
281	///
282	/// C: `static int luaB_corunning(lua_State *L)`
283	pub fn co_running(state: &mut LuaState) -> Result<usize, LuaError> {
284	    // C: int ismain = lua_pushthread(L);
285	    // TODO(port): push_thread pushes a Thread value for the current LuaState and
286	    // returns true iff it is the main thread; Phase B wire-up needed.
287	    let is_main = state.push_thread()?;
288	    // C: lua_pushboolean(L, ismain);
289	    state.push(LuaValue::Bool(is_main));
290	    Ok(2)
291	}
292	
293	/// `coroutine.close(co)` — close a dead or suspended coroutine.
294	///
295	/// Runs the to-be-closed variable finalizers.  Returns `true` on success, or
296	/// `false` plus an error object on failure.  Raises an error if `co` is
297	/// running or normal.
298	///
299	/// C: `static int luaB_close(lua_State *L)`
300	pub fn co_close(state: &mut LuaState) -> Result<usize, LuaError> {
301	    let co = get_co(state)?;
302	    let status = aux_status(state, &co);
303	    match status {
304	        s if s == COS_DEAD || s == COS_YIELD => {
305	            // TODO(phase-b): needs cross-thread close_thread + xmove.
306	            todo!("phase-b: coroutine close")
307	        }
308	        _ => {
309	            let name = match status {
310	                COS_RUN => "running",
311	                COS_NORM => "normal",
312	                _ => "unknown",
313	            };
314	            Err(LuaError::runtime(format_args!(
315	                "cannot close a {} coroutine",
316	                name
317	            )))
318	        }
319	    }
320	}
321	
322	// ── Module entry point ────────────────────────────────────────────────────────
323	
324	/// Opens the `coroutine` standard library by pushing a new table containing
325	/// all `coroutine.*` functions.
326	///
327	/// C: `LUAMOD_API int luaopen_coroutine(lua_State *L)` — `LUAMOD_API` → `pub`.
328	pub fn open_coroutine(state: &mut LuaState) -> Result<usize, LuaError> {
329	    // C: luaL_newlib(L, co_funcs);
330	    // TODO(port): state.new_lib(CO_FUNCS) creates a table from the registration
331	    // slice and leaves it on the stack; Phase B wire-up needed.
332	    state.new_lib(CO_FUNCS)?;
333	    Ok(1)
334	}
335	
336	// ──────────────────────────────────────────────────────────────────────────────
337	// PORT STATUS
338	//   source:        src/lcorolib.c  (210 lines, 12 functions)
339	//   target_crate:  lua-stdlib
340	//   confidence:    medium
341	//   todos:         21
342	//   port_notes:    2
343	//   unsafe_blocks: 0
344	//   notes:         All coroutine execution primitives (resume, yield, xmove,
345	//                  new_thread, close_thread) are Phase E stubs that panic.
346	//                  Argument-checking / result-packaging logic is faithfully
347	//                  translated so Phase E can drop in real implementations.
348	//                  The CO_FUNCS table type references lua_CFunction which is
349	//                  resolved in Phase B.  LuaState / GcRef<LuaState> / LuaStatus
350	//                  imports are all deferred to Phase B.
351	// ──────────────────────────────────────────────────────────────────────────────
